class Tokenizer {
  constructor(input) {
    this.input = input;
    this.index = 0;
    this.current = null;
  }

  peek() {
    if (!this.current) this.current = this.nextToken();
    return this.current;
  }

  next() {
    const token = this.peek();
    this.current = null;
    return token;
  }

  nextToken() {
    this.skipWhitespace();
    if (this.index >= this.input.length) return { type: "eof" };

    const ch = this.input[this.index];
    const two = this.input.slice(this.index, this.index + 2);
    const three = this.input.slice(this.index, this.index + 3);

    if (three === "===" || three === "!==") {
      this.index += 3;
      return { type: "operator", value: three };
    }

    if (["==", "!=", ">=", "<=", "&&", "||"].includes(two)) {
      this.index += 2;
      return { type: "operator", value: two };
    }

    if ("+-*/%()?:.!><".includes(ch)) {
      this.index += 1;
      return { type: "operator", value: ch };
    }

    if (ch === "'" || ch === '"') {
      return this.readString(ch);
    }

    if (isDigit(ch) || (ch === "." && isDigit(this.input[this.index + 1]))) {
      return this.readNumber();
    }

    if (isIdentifierStart(ch)) {
      return this.readIdentifier();
    }

    throw new Error(`Unexpected character: ${ch}`);
  }

  skipWhitespace() {
    while (this.index < this.input.length && /\s/.test(this.input[this.index])) {
      this.index += 1;
    }
  }

  readString(quote) {
    this.index += 1;
    let out = "";
    while (this.index < this.input.length) {
      const ch = this.input[this.index++];
      if (ch === quote) return { type: "string", value: out };
      if (ch === "\\") {
        const next = this.input[this.index++];
        out += escapeChar(next);
      } else {
        out += ch;
      }
    }
    throw new Error("Unterminated string literal");
  }

  readNumber() {
    const start = this.index;
    while (this.index < this.input.length && /[0-9.]/.test(this.input[this.index])) {
      this.index += 1;
    }
    const value = Number(this.input.slice(start, this.index));
    if (Number.isNaN(value)) throw new Error("Invalid number");
    return { type: "number", value };
  }

  readIdentifier() {
    const start = this.index;
    this.index += 1;
    while (this.index < this.input.length && isIdentifierPart(this.input[this.index])) {
      this.index += 1;
    }
    const value = this.input.slice(start, this.index);
    if (value === "true") return { type: "boolean", value: true };
    if (value === "false") return { type: "boolean", value: false };
    if (value === "null") return { type: "null", value: null };
    return { type: "identifier", value };
  }
}

function escapeChar(ch) {
