function evaluateExpression(expression, data) {
  const keys = Object.keys(data || {});
  const values = keys.map((key) => data[key]);

  const scope = new Proxy(
    {},
    {
      has: () => true,
      get: (_, prop) => {
        if (typeof prop !== "string") return undefined;
        if (prop in (data || {})) return data[prop];
